package main

import (
    "net/http"
    "time"
)

// Compliant: Cookie with Secure flag
func setSessionCookie(w http.ResponseWriter, sessionID string) {
    cookie := &http.Cookie{
        Name:     "session_id",
        Value:    sessionID,
        Path:     "/",
        Expires:  time.Now().Add(24 * time.Hour),
        HttpOnly: true,
        Secure:   true, // GOOD: Only transmitted over HTTPS
    }
    http.SetCookie(w, cookie)
}

func setAuthCookie(w http.ResponseWriter, token string) {
    // GOOD: Authentication cookie secured for HTTPS only
    cookie := &http.Cookie{
        Name:     "auth_token",
        Value:    token,
        Path:     "/",
        HttpOnly: true,
        Secure:   true, // GOOD: Ensures HTTPS-only transmission
        SameSite: http.SameSiteStrictMode,
    }
    http.SetCookie(w, cookie)
}

// Helper function to check if connection is secure
func setCookieSecurely(w http.ResponseWriter, r *http.Request, name, value string) {
    secure := r.TLS != nil || r.Header.Get("X-Forwarded-Proto") == "https"

    cookie := &http.Cookie{
        Name:     name,
        Value:    value,
        Path:     "/",
        HttpOnly: true,
        Secure:   secure, // GOOD: Secure flag based on connection type
    }
    http.SetCookie(w, cookie)
}
